import React, { useState, useEffect, useRef, useCallback } from "react";
import { io } from "socket.io-client";
import { useAuth } from "./AuthProvider";
import Header from "./Header";
import { useNavigate, useLocation, useParams } from "react-router-dom";
import { toast } from "react-toastify";

// ‚îÄ‚îÄ‚îÄ T√≠nh delta gi·ªØa 2 chu·ªói ‚Üí danh s√°ch operation nh·ªè ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
function diffToOperations(oldStr, newStr, documentId, clientId, revision) {
  let start = 0;
  while (start < oldStr.length && start < newStr.length && oldStr[start] === newStr[start]) start++;
  let oldEnd = oldStr.length;
  let newEnd = newStr.length;
  while (oldEnd > start && newEnd > start && oldStr[oldEnd - 1] === newStr[newEnd - 1]) { oldEnd--; newEnd--; }

  const ops = [];
  const deleted = oldStr.slice(start, oldEnd);
  const inserted = newStr.slice(start, newEnd);
  for (let i = 0; i < deleted.length; i++)
    ops.push({ type: "delete", position: start, documentId, clientId, revision });
  for (let i = 0; i < inserted.length; i++)
    ops.push({ type: "insert", position: start + i, char: inserted[i], documentId, clientId, revision });
  return ops;
}

// ‚îÄ‚îÄ‚îÄ √Åp d·ª•ng 1 operation l√™n chu·ªói ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
function applyOp(content, op) {
  if (op.type === "insert" && op.position >= 0) {
    const pos = Math.min(op.position, content.length);
    return content.slice(0, pos) + (op.char ?? "") + content.slice(pos);
  }
  if (op.type === "delete" && op.position >= 0 && op.position < content.length) {
    return content.slice(0, op.position) + content.slice(op.position + 1);
  }
  return content;
}

export default function Editor() {
  const navigate = useNavigate();
  const location = useLocation();
  const { documentId: docIdFromUrl } = useParams();
  const { user: loggedInUser } = useAuth();

  const initialDocumentId = docIdFromUrl ?? location.state?.documentId ?? null;

  const [documentId, setDocumentId] = useState(initialDocumentId);
  const [title, setTitle] = useState(location.state?.title ?? "");
  const [content, setContent] = useState(location.state?.content ?? "");
  const [revision, setRevision] = useState(0);
  const [activeUsers, setActiveUsers] = useState(1);
  const [lastSaved, setLastSaved] = useState(null);
  const [bold, setBold] = useState(false);
  const [italic, setItalic] = useState(false);
  const [underline, setUnderline] = useState(false);
  const [typingUsers, setTypingUsers] = useState([]);
  const [messages, setMessages] = useState([]);
  const [inputMsg, setInputMsg] = useState("");
  const [connected, setConnected] = useState(false);

  // Refs ƒë·ªÉ tr√°nh stale closure trong event handler
  const contentRef = useRef(content);
  const revisionRef = useRef(0);
  const documentIdRef = useRef(documentId);
  const isRemote = useRef(false);
  const typingTimer = useRef(null);
  const socketRef = useRef(null);

  contentRef.current = content;
  revisionRef.current = revision;
  documentIdRef.current = documentId;

  // ‚îÄ‚îÄ‚îÄ Ki·ªÉm tra ƒêƒÉng nh·∫≠p ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
  useEffect(() => {
    if (!loggedInUser) {
      toast.warning("Vui l√≤ng ƒëƒÉng nh·∫≠p tr∆∞·ªõc ƒë·ªÉ xem/ch·ªânh s·ª≠a t√Ýi li·ªáu!");
      const targetPath = documentId ? `/editor/${documentId}` : "/editor";
      navigate("/", { state: { from: targetPath } });
    }
  }, [loggedInUser, documentId, navigate]);

  // ‚îÄ‚îÄ‚îÄ Kh·ªüi t·∫°o socket 1 l·∫ßn, join room sau khi connected ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
  useEffect(() => {
    const socket = io("http://localhost:3000", { transports: ["websocket"] });
    socketRef.current = socket;

    socket.on("connect", () => {
      console.log("[Socket] Connected:", socket.id);
      setConnected(true);

      // Join room ngay sau khi connect ‚Äî ƒë·∫£m b·∫£o socket ƒë√£ s·∫µn s√Ýng
      if (documentIdRef.current && loggedInUser) {
        socket.emit("join-document", {
          documentId: documentIdRef.current,
          fullname: loggedInUser.fullname,
          email: loggedInUser.email,
        });
      }
    });

    socket.on("disconnect", () => {
      console.log("[Socket] Disconnected");
      setConnected(false);
    });

    // Nh·∫≠n tr·∫°ng th√°i ban ƒë·∫ßu khi join room
    socket.on("document-init", ({ content: c, revision: rev, title: t }) => {
      console.log("[Socket] document-init, revision:", rev);
      isRemote.current = true;
      setContent(c ?? "");
      setRevision(rev ?? 0);
      revisionRef.current = rev ?? 0;
      if (t !== undefined) setTitle(t);
      isRemote.current = false;
    });

    // Nh·∫≠n operation t·ª´ ng∆∞·ªùi kh√°c ‚Üí √°p d·ª•ng tr·ª±c ti·∫øp
    socket.on("remote-operation", ({ op, revision: newRev }) => {
      isRemote.current = true;
      setContent((prev) => applyOp(prev, op));
      setRevision(newRev);
      revisionRef.current = newRev;
      isRemote.current = false;
    });

    // Nh·∫≠n thay ƒë·ªïi ti√™u ƒë·ªÅ t·ª´ ng∆∞·ªùi kh√°c
    socket.on("remote-title", ({ title: newTitle }) => {
      setTitle(newTitle);
    });

    socket.on("ack", ({ revision: newRev }) => {
      setRevision(newRev);
      revisionRef.current = newRev;
    });

    socket.on("auto-saved", ({ savedAt }) => {
      setLastSaved(new Date(savedAt).toLocaleTimeString("vi-VN"));
    });

    socket.on("save-document-success", (data) => {
      if (data._id && !documentIdRef.current) {
        setDocumentId(data._id);
        documentIdRef.current = data._id;
        window.history.replaceState(null, "", `/editor/${data._id}`);
      }
      toast.success(`ƒê√£ l∆∞u "${data.title ?? title}"`);
    });

    socket.on("active-users", ({ count }) => setActiveUsers(count));
    socket.on("user-joined", ({ fullname }) => toast.info(`${fullname} v·ª´a tham gia`));
    socket.on("user-left", () => setActiveUsers((n) => Math.max(1, n - 1)));

    socket.on("typing_indicator", ({ fullname, isTyping }) => {
      setTypingUsers((prev) =>
        isTyping ? (prev.includes(fullname) ? prev : [...prev, fullname])
                 : prev.filter((u) => u !== fullname)
      );
    });

    socket.on("received_message", ({ message }) => setMessages((prev) => [...prev, message]));
    socket.on("updateStyleBold", setBold);
    socket.on("updateStyleItalic", setItalic);
    socket.on("updateStyleUnderline", setUnderline);

    return () => { socket.disconnect(); };
  }, []); // ch·ªâ ch·∫°y 1 l·∫ßn khi mount

  // ‚îÄ‚îÄ‚îÄ Join document khi loggedInUser load xong (n·∫øu ch∆∞a join l√∫c connect) ‚îÄ‚îÄ‚îÄ
  useEffect(() => {
    const socket = socketRef.current;
    if (!socket || !loggedInUser || !documentId) return;
    if (socket.connected) {
      socket.emit("join-document", {
        documentId,
        fullname: loggedInUser.fullname,
        email: loggedInUser.email,
      });
    }
    // N·∫øu ch∆∞a connected, s·∫Ω join trong handler "connect" ·ªü tr√™n
  }, [loggedInUser, documentId]);

  // ‚îÄ‚îÄ‚îÄ Thay ƒë·ªïi n·ªôi dung ‚Üí g·ª≠i delta ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
  const handleContentChange = useCallback((e) => {
    const newContent = e.target.value;
    const oldContent = contentRef.current;
    const socket = socketRef.current;
    const docId = documentIdRef.current;

    if (!isRemote.current && docId && socket?.connected) {
      const ops = diffToOperations(oldContent, newContent, docId, socket.id, revisionRef.current);
      ops.forEach((op) => socket.emit("operation", op));
    }

    setContent(newContent);

    // Typing indicator
    clearTimeout(typingTimer.current);
    const docId2 = documentIdRef.current;
    socket?.emit("user_start_typing", { roomId: docId2, fullname: loggedInUser?.fullname, email: loggedInUser?.email });
    typingTimer.current = setTimeout(() => {
      socket?.emit("user_stop_typing", { roomId: docId2, fullname: loggedInUser?.fullname });
    }, 1500);
  }, [loggedInUser]);

  // ‚îÄ‚îÄ‚îÄ Thay ƒë·ªïi ti√™u ƒë·ªÅ ‚Üí broadcast cho room ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
  const handleTitleChange = useCallback((e) => {
    const newTitle = e.target.value;
    setTitle(newTitle);
    const socket = socketRef.current;
    const docId = documentIdRef.current;
    if (docId && socket?.connected) {
      socket.emit("title-change", { documentId: docId, title: newTitle });
    }
  }, []);

  // ‚îÄ‚îÄ‚îÄ Style ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
  const handleBold = () => { const v = !bold; setBold(v); socketRef.current?.emit("updateStyleBold", { documentId, bold: v }); };
  const handleItalic = () => { const v = !italic; setItalic(v); socketRef.current?.emit("updateStyleItalic", { documentId, italic: v }); };
  const handleUnderline = () => { const v = !underline; setUnderline(v); socketRef.current?.emit("updateStyleUnderline", { documentId, underline: v }); };

  // ‚îÄ‚îÄ‚îÄ Save ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
  const handleSave = () => {
    socketRef.current?.emit("save-document", {
      documentId,
      title,
      content,
      clientId: socketRef.current?.id,
      fullname: loggedInUser?.fullname,
      email: loggedInUser?.email,
    });
  };

  // ‚îÄ‚îÄ‚îÄ Copy share link ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
  const handleCopyLink = () => {
    if (!documentId) { toast.warning("L∆∞u t√Ýi li·ªáu tr∆∞·ªõc ƒë·ªÉ t·∫°o link!"); return; }
    navigator.clipboard.writeText(`${window.location.origin}/editor/${documentId}`);
    toast.success("ƒê√£ copy link chia s·∫ª!");
  };

  // ‚îÄ‚îÄ‚îÄ Chat ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
  const sendMessage = () => {
    if (!inputMsg.trim()) return;
    socketRef.current?.emit("send_message", { room: documentId, message: inputMsg });
    setInputMsg("");
  };

  return (
    <div className="min-h-screen bg-gradient-to-r from-blue-400 to-blue-100">
      <Header />
      <div className="container mx-auto px-4 py-8 md:w-3/4 bg-gradient-to-r from-purple-500 to-purple-300 rounded-lg shadow-lg">

        {/* Status bar */}
        <div className="flex justify-between items-center mb-3 text-sm text-white">
          <span className="font-bold">
            üë§ {loggedInUser?.fullname}
            <span className={`ml-2 text-xs ${connected ? "text-green-300" : "text-red-300"}`}>
              ‚óè {connected ? "ƒê√£ k·∫øt n·ªëi" : "ƒêang k·∫øt n·ªëi..."}
            </span>
          </span>
          <span>
            üü¢ {activeUsers} ng∆∞·ªùi ƒëang ch·ªânh s·ª≠a
            {lastSaved && <span className="ml-3 opacity-75">üíæ {lastSaved}</span>}
          </span>
          <span className="opacity-75 text-xs">rev.{revision}</span>
        </div>

        {/* Share link */}
        {documentId && (
          <div className="flex items-center gap-2 mb-3 bg-white bg-opacity-20 rounded-lg px-3 py-2">
            <span className="text-white text-xs flex-shrink-0">üîó</span>
            <input
              readOnly
              value={`${window.location.origin}/editor/${documentId}`}
              className="flex-1 text-xs bg-transparent text-white outline-none truncate"
              onFocus={(e) => e.target.select()}
            />
            <button onClick={handleCopyLink} className="flex-shrink-0 bg-white text-purple-700 text-xs font-bold px-3 py-1 rounded-md hover:bg-purple-100">
              Copy
            </button>
          </div>
        )}

        {/* Ti√™u ƒë·ªÅ ‚Äî ƒë·ªìng b·ªô real-time */}
        <div className="mb-4">
          <input
            type="text"
            className="w-full p-4 border border-gray-300 rounded-lg focus:outline-none focus:border-blue-500"
            value={title}
            onChange={handleTitleChange}
            placeholder="Ti√™u ƒë·ªÅ t√Ýi li·ªáu..."
          />
        </div>

        {/* Typing indicator */}
        {typingUsers.length > 0 && (
          <p className="text-center text-white text-sm mb-2">{typingUsers.join(", ")} ƒëang g√µ...</p>
        )}

        {/* Toolbar */}
        <div className="flex justify-between mb-4">
          <div className="flex gap-2">
            <button className={`px-4 py-2 rounded-md text-white ${bold ? "bg-orange-800" : "bg-orange-600 hover:bg-orange-700"}`} onClick={handleBold}><b>B</b></button>
            <button className={`px-4 py-2 rounded-md text-white ${italic ? "bg-green-800" : "bg-green-600 hover:bg-green-700"}`} onClick={handleItalic}><i>I</i></button>
            <button className={`px-4 py-2 rounded-md text-white ${underline ? "bg-orange-800" : "bg-orange-600 hover:bg-orange-700"}`} onClick={handleUnderline}><u>U</u></button>
          </div>
          <div className="flex gap-2">
            <button className="px-4 py-2 bg-green-500 text-white rounded-md hover:bg-green-600" onClick={handleSave}>üíæ L∆∞u</button>
            <button className="px-4 py-2 bg-yellow-500 text-white rounded-md hover:bg-yellow-600" onClick={handleCopyLink}>üîó Share</button>
            <button className="px-4 py-2 bg-red-500 text-white rounded-md hover:bg-red-600" onClick={() => navigate("/view-documents")}>üìÑ Danh s√°ch</button>
          </div>
        </div>

        {/* N·ªôi dung ‚Äî ƒë·ªìng b·ªô real-time */}
        <textarea
          className="w-full h-80 border border-gray-300 rounded-lg p-4 resize-none focus:outline-none focus:border-blue-500"
          value={content}
          onChange={handleContentChange}
          placeholder="B·∫Øt ƒë·∫ßu g√µ n·ªôi dung t√Ýi li·ªáu..."
          style={{
            fontWeight: bold ? "bold" : "normal",
            fontStyle: italic ? "italic" : "normal",
            textDecoration: underline ? "underline" : "none",
          }}
        />

        {/* Chat */}
        <div className="flex gap-2 mt-4">
          <input
            type="text"
            className="flex-1 border rounded py-2 px-4"
            value={inputMsg}
            onChange={(e) => setInputMsg(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && sendMessage()}
            placeholder="Nh·∫Øn tin trong room..."
          />
          <button className="bg-green-500 hover:bg-green-700 text-white font-bold py-2 px-4 rounded" onClick={sendMessage}>G·ª≠i</button>
        </div>

        {messages.length > 0 && (
          <>
            <h2 className="mt-4 mb-2 font-bold text-white">Tin nh·∫Øn:</h2>
            <ul>{messages.map((m, i) => <li key={i} className="bg-gray-200 p-2 rounded mb-2 text-sm">{m}</li>)}</ul>
          </>
        )}
      </div>
    </div>
  );
}
